import java.util.HashMap;
import java.util.Map;

public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        int q = queries.length;
        long[] ans = new long[q];
        for (int i = 0; i < q; i++) {
            long l = queries[i][0];
            long r = queries[i][1];
            long threshold = queries[i][2];
            HashMap<Long, Long> freqMap = new HashMap<>();
            for (int j = (int) l; j <= (int) r; j++) {
                long num = nums[j];
                freqMap.put(num, freqMap.getOrDefault(num, 0L) + 1);
            }
            long maxFreq = -1;
            long ansEle = -1;
            for (Map.Entry<Long, Long> entry : freqMap.entrySet()) {
                long freq = entry.getValue();
                if (freq >= threshold) {
                    if (freq > maxFreq || (freq == maxFreq && entry.getKey() < ansEle)) {
                        maxFreq = freq;
                        ansEle = entry.getKey();
                    }
                }
            }
            ans[i] = ansEle;
        }
        return ans;
    }
}
